import{c as s,Q as i,j as n,m as l}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"OS 在云原生时代","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/28-OS在云原生时代.md","filePath":"osLearning/28-OS在云原生时代.md","lastUpdated":1778496697000}'),e={name:"osLearning/28-OS在云原生时代.md"};function p(t,a,h,r,o,c){return i(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="os-在云原生时代" tabindex="-1">OS 在云原生时代 <a class="header-anchor" href="#os-在云原生时代" aria-label="Permalink to &quot;OS 在云原生时代&quot;">​</a></h1><p>学完 CPU、内存、进程、线程、IO、文件、容器和 eBPF,你会发现云原生并没有绕开 OS,反而把 OS 问题放大了:容器 CPU quota 导致 p99 抖动,cgroup OOM 杀进程,OverlayFS 影响写放大,Service Mesh 增加 socket 和上下文切换,eBPF 接管网络和观测。最后一篇把这条线收住:<strong>现代后端工程师为什么仍然必须懂 OS,以及未来 Linux 内核演进会把性能问题带向哪里</strong>。</p><blockquote><p>一句话先记住:<strong>云原生不是 OS 的替代品,而是 OS 抽象的大规模编排</strong>。K8s 调 Pod,本质还是调 Linux 进程;Service Mesh 转流量,本质还是 socket 和 iptables/eBPF;Serverless 冷启动,本质还是进程/容器/文件系统加载。<strong>越往云上走,越需要用 OS 视角解释性能和稳定性</strong>。</p></blockquote><hr><h2 id="一、这-28-篇的主线" tabindex="-1">一、这 28 篇的主线 <a class="header-anchor" href="#一、这-28-篇的主线" aria-label="Permalink to &quot;一、这 28 篇的主线&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU:      程序如何真正执行</span></span>
<span class="line"><span>内存:     虚拟地址、页表、分配、缓存</span></span>
<span class="line"><span>并发:     进程、线程、锁、调度、协程</span></span>
<span class="line"><span>IO:       fd、文件系统、epoll、io_uring、零拷贝</span></span>
<span class="line"><span>工程:     信号、容器、性能工具、eBPF</span></span></code></pre></div><p>这不是孤立知识点,而是一条性能路径:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>代码慢</span></span>
<span class="line"><span>  → CPU cache miss?</span></span>
<span class="line"><span>  → syscall 太多?</span></span>
<span class="line"><span>  → 锁竞争?</span></span>
<span class="line"><span>  → 调度延迟?</span></span>
<span class="line"><span>  → page fault?</span></span>
<span class="line"><span>  → IO wait?</span></span>
<span class="line"><span>  → cgroup throttle?</span></span>
<span class="line"><span>  → 网络栈/文件系统?</span></span></code></pre></div><hr><h2 id="二、云原生把-os-问题重新包装" tabindex="-1">二、云原生把 OS 问题重新包装 <a class="header-anchor" href="#二、云原生把-os-问题重新包装" aria-label="Permalink to &quot;二、云原生把 OS 问题重新包装&quot;">​</a></h2><h3 id="_2-1-pod-是进程组" tabindex="-1">2.1 Pod 是进程组 <a class="header-anchor" href="#_2-1-pod-是进程组" aria-label="Permalink to &quot;2.1 Pod 是进程组&quot;">​</a></h3><p>K8s Pod 看起来是调度单元,落到节点上是:</p><ul><li>namespace</li><li>cgroup</li><li>rootfs</li><li>pause container</li><li>一组进程</li></ul><p>Pod Pending 是调度问题;Pod Running 后的性能,大多仍是 Linux 问题。</p><h3 id="_2-2-cpu-limit-是调度问题" tabindex="-1">2.2 CPU limit 是调度问题 <a class="header-anchor" href="#_2-2-cpu-limit-是调度问题" aria-label="Permalink to &quot;2.2 CPU limit 是调度问题&quot;">​</a></h3><p><code>resources.limits.cpu: 500m</code> 不是&quot;半个 CPU 慢慢跑&quot;,而是 CFS quota:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一个周期内跑够 quota → throttle</span></span></code></pre></div><p>这会把突发 CPU 变成延迟尖刺。</p><h3 id="_2-3-memory-limit-是-oom-边界" tabindex="-1">2.3 memory limit 是 OOM 边界 <a class="header-anchor" href="#_2-3-memory-limit-是-oom-边界" aria-label="Permalink to &quot;2.3 memory limit 是 OOM 边界&quot;">​</a></h3><p>容器内超过 memory limit,触发 cgroup OOM。JVM/Go/Node 必须感知容器限制,否则会按宿主机资源估算堆和线程。</p><h3 id="_2-4-overlayfs-是文件系统问题" tabindex="-1">2.4 OverlayFS 是文件系统问题 <a class="header-anchor" href="#_2-4-overlayfs-是文件系统问题" aria-label="Permalink to &quot;2.4 OverlayFS 是文件系统问题&quot;">​</a></h3><p>容器可写层适合临时文件,不适合高频持久写。数据库、日志、对象数据应放 volume。</p><hr><h2 id="三、service-mesh-和网络栈" tabindex="-1">三、Service Mesh 和网络栈 <a class="header-anchor" href="#三、service-mesh-和网络栈" aria-label="Permalink to &quot;三、Service Mesh 和网络栈&quot;">​</a></h2><p>Sidecar 模式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应用 → localhost → sidecar → 网络 → sidecar → 应用</span></span></code></pre></div><p>代价:</p><ul><li>连接数增加</li><li>socket buffer 增加</li><li>syscall 增加</li><li>TLS 加解密增加</li><li>上下文切换增加</li><li>延迟链路变长</li></ul><p>Ambient mesh/eBPF 数据面尝试减少 sidecar 成本,但本质仍在 Linux 网络路径上做取舍。</p><hr><h2 id="四、serverless-和冷启动" tabindex="-1">四、Serverless 和冷启动 <a class="header-anchor" href="#四、serverless-和冷启动" aria-label="Permalink to &quot;四、Serverless 和冷启动&quot;">​</a></h2><p>冷启动涉及:</p><ul><li>拉镜像</li><li>解压/挂载 rootfs</li><li>创建 namespace/cgroup</li><li>启动进程</li><li>加载动态库</li><li>JIT/运行时初始化</li><li>预热连接</li></ul><p>优化手段:</p><ul><li>更小镜像</li><li>lazy pull</li><li>snapshot</li><li>Firecracker microVM</li><li>预热池</li><li>减少动态初始化</li></ul><p>这些都离不开 OS 的进程、文件系统、虚拟化和调度。</p><hr><h2 id="五、现代-linux-的方向" tabindex="-1">五、现代 Linux 的方向 <a class="header-anchor" href="#五、现代-linux-的方向" aria-label="Permalink to &quot;五、现代 Linux 的方向&quot;">​</a></h2><h3 id="_5-1-io-uring" tabindex="-1">5.1 io_uring <a class="header-anchor" href="#_5-1-io-uring" aria-label="Permalink to &quot;5.1 io_uring&quot;">​</a></h3><p>把同步 syscall IO 推向异步队列模型。未来高性能存储、代理、数据库会更多使用。</p><h3 id="_5-2-ebpf" tabindex="-1">5.2 eBPF <a class="header-anchor" href="#_5-2-ebpf" aria-label="Permalink to &quot;5.2 eBPF&quot;">​</a></h3><p>把观测、网络、安全逻辑从&quot;改内核/sidecar&quot;转向&quot;安全内核程序&quot;。</p><h3 id="_5-3-cgroup-v2" tabindex="-1">5.3 cgroup v2 <a class="header-anchor" href="#_5-3-cgroup-v2" aria-label="Permalink to &quot;5.3 cgroup v2&quot;">​</a></h3><p>统一资源控制层次,更适合容器和 systemd 管理。</p><h3 id="_5-4-rust-for-linux" tabindex="-1">5.4 Rust for Linux <a class="header-anchor" href="#_5-4-rust-for-linux" aria-label="Permalink to &quot;5.4 Rust for Linux&quot;">​</a></h3><p>降低内核内存安全风险,但不会一夜之间改写整个内核。</p><h3 id="_5-5-硬件趋势" tabindex="-1">5.5 硬件趋势 <a class="header-anchor" href="#_5-5-硬件趋势" aria-label="Permalink to &quot;5.5 硬件趋势&quot;">​</a></h3><ul><li>多核更多,NUMA 更常见</li><li>SSD/NVMe 延迟更低,syscall 更显贵</li><li>SmartNIC/DPU 把网络处理下沉</li><li>ARM 服务器普及,弱内存序更重要</li></ul><hr><h2 id="六、后端工程师该形成的-os-直觉" tabindex="-1">六、后端工程师该形成的 OS 直觉 <a class="header-anchor" href="#六、后端工程师该形成的-os-直觉" aria-label="Permalink to &quot;六、后端工程师该形成的 OS 直觉&quot;">​</a></h2><h3 id="_6-1-看到延迟-先问等待在哪里" tabindex="-1">6.1 看到延迟,先问等待在哪里 <a class="header-anchor" href="#_6-1-看到延迟-先问等待在哪里" aria-label="Permalink to &quot;6.1 看到延迟,先问等待在哪里&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU run queue?</span></span>
<span class="line"><span>锁?</span></span>
<span class="line"><span>IO?</span></span>
<span class="line"><span>网络?</span></span>
<span class="line"><span>GC?</span></span>
<span class="line"><span>cgroup throttle?</span></span>
<span class="line"><span>下游?</span></span></code></pre></div><h3 id="_6-2-看到内存-先分清虚拟和物理" tabindex="-1">6.2 看到内存,先分清虚拟和物理 <a class="header-anchor" href="#_6-2-看到内存-先分清虚拟和物理" aria-label="Permalink to &quot;6.2 看到内存,先分清虚拟和物理&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VIRT 不等于 RSS</span></span>
<span class="line"><span>RSS 不等于堆</span></span>
<span class="line"><span>page cache 不等于泄漏</span></span>
<span class="line"><span>container limit 不等于宿主机内存</span></span></code></pre></div><h3 id="_6-3-看到并发-先问调度和共享" tabindex="-1">6.3 看到并发,先问调度和共享 <a class="header-anchor" href="#_6-3-看到并发-先问调度和共享" aria-label="Permalink to &quot;6.3 看到并发,先问调度和共享&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>线程数是否超过核数太多?</span></span>
<span class="line"><span>锁是否竞争?</span></span>
<span class="line"><span>cache line 是否抖动?</span></span>
<span class="line"><span>协程是否被阻塞 syscall 卡住?</span></span></code></pre></div><h3 id="_6-4-看到-io-先问路径" tabindex="-1">6.4 看到 IO,先问路径 <a class="header-anchor" href="#_6-4-看到-io-先问路径" aria-label="Permalink to &quot;6.4 看到 IO,先问路径&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>page cache 命中?</span></span>
<span class="line"><span>fsync?</span></span>
<span class="line"><span>小 IO 还是大 IO?</span></span>
<span class="line"><span>epoll 还是线程池?</span></span>
<span class="line"><span>copy 是否打满 CPU?</span></span></code></pre></div><hr><h2 id="七、学习边界" tabindex="-1">七、学习边界 <a class="header-anchor" href="#七、学习边界" aria-label="Permalink to &quot;七、学习边界&quot;">​</a></h2><p>这套系列到这里已经足够支撑工程排障和性能调优。再往下有三个方向:</p><ol><li><strong>内核源码</strong>:调度器、内存管理、网络栈、文件系统源码。</li><li><strong>系统编程</strong>:C/Rust 写网络库、存储引擎、runtime。</li><li><strong>性能工程</strong>:benchmark、profiling、容量规划、SLO。</li></ol><p>不要为了&quot;懂内核&quot;而逐行读源码。带问题读:</p><ul><li>为什么 futex 卡住?</li><li>为什么 page cache 不回收?</li><li>为什么 TCP 重传?</li><li>为什么 fsync 抖动?</li></ul><hr><h2 id="八、最后的排障模板" tabindex="-1">八、最后的排障模板 <a class="header-anchor" href="#八、最后的排障模板" aria-label="Permalink to &quot;八、最后的排障模板&quot;">​</a></h2><p>线上问题先收证据:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">date</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uptime</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">top</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vmstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">free</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iostat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pidstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -urdw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dmesg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -100</span></span></code></pre></div><p>再下钻:</p><ul><li>CPU → perf / flamegraph</li><li>syscall → strace / bpftrace</li><li>IO → iostat / biolatency</li><li>调度 → perf sched / runqlat</li><li>网络 → ss / tcpdump / tcpretrans</li><li>内存 → smaps / heap profile / OOM log</li></ul><hr><h2 id="九、总结" tabindex="-1">九、总结 <a class="header-anchor" href="#九、总结" aria-label="Permalink to &quot;九、总结&quot;">​</a></h2><p>OS 系列真正要建立的是一套心智:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应用现象</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>运行时行为</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>系统调用</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>内核机制</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>硬件约束</span></span></code></pre></div><p>当你能把一个 p99 抖动问题从 HTTP handler 一路追到 cgroup throttle、futex、page fault、TCP retrans 或 fsync,你就不再是在&quot;猜性能&quot;,而是在做工程。</p><blockquote><p><strong>结尾一句话</strong>:现代工程不是离 OS 越来越远,而是抽象越来越厚。抽象可以帮你交付,但排障时必须有能力把它一层层拆回 Linux。</p></blockquote>`,76)])])}const k=s(e,[["render",p]]);export{u as __pageData,k as default};
